sp_widget.client_script:
api.controller = function($scope, $timeout,spUtil,$location) {
    var c = this;

    c.activeTab = 'createModel';
    c.dataModels = [];
		c.objectTables=[];
    c.previewHeaders = [];

    c.mappings = [];
    c.pagedMappings = [];
    c.mappingPageNumber = 1;
    c.mappingPageSize = 10;  /* CHANGE 1: was 5, now 10 rows per page */
    c.mappingTotalPages = 1;
    c.newModel = {};
    c.disclaimer = {};
    c.modelCreated = false;
    c.modelMessage = '';
    c.modelError = '';
    c.mappingError = '';
    c.mappingSuccess = '';
    c.modelLoading = false;
    c.saveMappingDone = false;
		c.newModel.data_source_system="Internal";
		c.newModel.source_name="ServiceNow";
		c.newModel.source_type="direct";
		c.dataModelObject="";




	getDataTypes();

		function getDataTypes() {

		c.server.get({
				action: 'getDataTypes'
		}).then(function(res) {

				c.dataTypes = res.data.dataTypes || [];

		});
		}


	getModels();
		function getModels()
	{
		 c.server.get({
        action: 'getDataModels'
    }).then(function(res) {
        c.dataModels = res.data.dataModels;
    });
	}

	getObjectTables();
		function getObjectTables()
	{

		 c.server.get({
        action: 'getObjectTables'
    }).then(function(res) {
        c.objectTables = res.data.objectTables;

    }); 
	}


    c.setTab = function(tab) {

        c.activeTab = tab;
			if(c.activeTab=="preview")
			{
				spUtil.get('incentnow-table-widget', {
							table: c.newModel.objectTable.name,
							view: 'Default view',
							page_size: '10'
						}).then(function(response) {
								c.childWidget = response;
						});


			}
    };




	c.setObjectName = function() {

    if (c.newModel.objectTable) {

        c.newModel.object_name = c.newModel.objectTable.label;

			c.loadOpportunityFields();
    } else {

        c.newModel.object_name = '';

    }
};

	c.loadOpportunityFields = function() {

			c.server.get({
					action: 'getOpportunityFields',
					table_name: c.newModel.objectTable.name
			}).then(function(res) {

					c.previewHeaders = [];

					res.data.previewHeaders.forEach(function(field) {
							c.previewHeaders = res.data.previewHeaders;
					});

					c.generateMappings();
			});


			};



    /* REQ-1: Create Model — fades on click, stays faded after success */
    c.createModel = function() {
        c.modelCreated = false;
        c.modelMessage = '';
        c.modelError = '';

        if (!c.newModel.source_name ||
            !c.newModel.source_type ||
            !c.newModel.object_name || !c.newModel.data_source_system) {
            c.modelError = 'All fields are required.';
            return;
        }

           /* fade immediately on click */
        c.data.action = 'createModel';
        c.data.model = c.newModel;

        c.server.update().then(function(response) {
            //var d = response.data;
						if(response.success==false && response.newModelId)
							{
								spUtil.addErrorMessage(response.error);
								c.dataModelObject=response.newModelId;
								c.modelCreated=true;
								c.modelLoading = false;
								$location.url("/incentiq?id=view_data_model_internal");

							}
					else if(response.success==true)
						{
							c.dataModelObject=response.newModelId;
							c.modelCreated=true;
							c.modelLoading = true;
							spUtil.addInfoMessage(response.message);
						}
					else
						spUtil.addErrorMessage(response.error);

        });

    };


	c.generateMappings = function() {
			c.mappings = [];
			c.previewHeaders.forEach(function(field) {
					c.mappings.push({
							source: field.name,
							dataType: field.internal_type,
							fieldTypeSysId: field.field_type_sys_id,
							targetField: '',
							isPrimary: false,
							sourceDisplayName: field.label,
							availableTargets: [],
							allTargets: []
					});
			});
			c.mappingPageNumber = 1;
			c.updateMappingPagination();
			};


    c.updateMappingPagination = function() {
        var start = (c.mappingPageNumber - 1) * c.mappingPageSize;
        c.pagedMappings = c.mappings.slice(start, start + c.mappingPageSize);
        c.mappingTotalPages = Math.ceil(c.mappings.length / c.mappingPageSize);
    };

    c.nextMappingPage = function() {
        if (c.mappingPageNumber < c.mappingTotalPages) {
            c.mappingPageNumber++;
            c.updateMappingPagination();
        }
    };
    c.prevMappingPage = function() {
        if (c.mappingPageNumber > 1) {
            c.mappingPageNumber--;
            c.updateMappingPagination();
        }
    };

    c.isDisclaimerField = function(source) {
        return (c.disclaimer.targetUserId && c.disclaimer.targetUserId === source) ||
            (c.disclaimer.transactionDate && c.disclaimer.transactionDate === source);
    };

    c.updateFilteredMappings = function() {
        c.mappingPageNumber = 1;
        c.updateMappingPagination();
    };



    c.validateMandatoryFields = function() {
        c.mappingError = '';
        c.mappingSuccess = '';

        if (!c.disclaimer.targetUserId || !c.disclaimer.transactionDate) {
            c.mappingError = 'All fields are required. Please select User ID and Transaction Date.';
            return false;
        }

        var visibleMappings = c.mappings.filter(function(m) {
            return !c.isDisclaimerField(m.source);
        });

        var missingDisplay = visibleMappings.some(function(m) {
            return !m.sourceDisplayName || m.sourceDisplayName.trim() === '';
        });

        if (missingDisplay) {
            c.mappingError = 'All fields are required. Please fill in all Source Display Name fields.';
            return false;
        }

        return true;
    };


    c.saveMapping = function() {



        if (!c.validateMandatoryFields()) return;



        //c.saveMappingDone = true;   /* fade button immediately, stays faded */

        var clean = [];
        c.mappings.forEach(function(m) {
            if (c.isDisclaimerField(m.source)) return;

					clean.push({
								source: m.source || '',
								dataType: m.dataType || '',
								fieldTypeSysId: m.fieldTypeSysId || '',
								targetField: m.targetField || '',
								isPrimary: m.isPrimary ? true : false,
								sourceDisplayName: m.sourceDisplayName || ''
								});


        });
			//spUtil.addErrorMessage("Clean "+JSON.stringify(clean));

			if (c.disclaimer.targetUserId) {

						var userField = c.previewHeaders.find(function(h) {
								return h.name === c.disclaimer.targetUserId;
						});

						clean.push({
								source: c.disclaimer.targetUserId,
								targetField: 'user_id',
								dataType: 'string',
								fieldTypeSysId: userField ? userField.field_type_sys_id : '',
								sourceDisplayName: userField ? userField.label : c.disclaimer.targetUserId,
								isPrimary: false
						});
				}

				if (c.disclaimer.transactionDate) {

						var dateField = c.previewHeaders.find(function(h) {
								return h.name === c.disclaimer.transactionDate;
						});

						clean.push({
								source: c.disclaimer.transactionDate,
								targetField: 'transaction_date',
								dataType: 'glide_date_time',
								fieldTypeSysId: dateField ? dateField.field_type_sys_id : '',
								sourceDisplayName: dateField ? dateField.label : c.disclaimer.transactionDate,
								isPrimary: false
						});
				}

      /*  if (c.disclaimer.targetUserId) {
            clean.push({
                source: c.disclaimer.targetUserId,
                targetField: 'user_id',
                dataType: 'string',
                isPrimary: false
            });
        }
        if (c.disclaimer.transactionDate) {
            clean.push({
                source: c.disclaimer.transactionDate,
                targetField: 'transaction_date',
                dataType: 'glide_date_time',
                isPrimary: false
            });
        } */
        c.data.action = 'saveMapping';
        c.data.dataModelObject = c.dataModelObject;
        c.data.mappings = clean;

        c.server.update().then(function(r) {
            $timeout(function() {
                /* NOTE: saveMappingDone stays true — button stays faded */
                /* It is reset to false only when user closes the success banner (in HTML) */
								//spUtil.addErrorMessage("timeout "+JSON.stringify(r.error));
                if (r.error) {
                    c.saveMappingDone = false;   /* re-enable only on error */
                    c.mappingError = r.error;
                    c.mappingSuccess = '';
                } else {
                    c.mappingSuccess = 'Mapping saved successfully';
                    c.mappingError = '';
                }
            });
        });
    };





};

sp_widget.css:
/* ===============================================================
   UPLOAD WIDGET
=============================================================== */

html, body {
  height: 100%;
  margin: 0;
  background: #f0f2f5;
  font-family: "Inter", "Segoe UI", Roboto, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
}

.upload-page-wrap {
  display: flex;
  flex-direction: column;
  min-height: 100%;
  background: #f0f2f5;
}


select:disabled {
    background-color: #f3f4f6;
    cursor: not-allowed;
    opacity: 1;
}

input:disabled {
    background-color: #f3f4f6;
    cursor: not-allowed;
    opacity: 1;
}

/* ================= TOPBAR — blended with page background ================= */

.upload-page-topbar {
  background: transparent;
  padding: 0;
  margin-bottom: 0;
  border-bottom: none;
}

.upload-page-topbar-inner {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 24px 28px 8px;
}

.upload-back-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: #e2e8f0;
  border: none;
  cursor: pointer;
  color: #374151;
  flex-shrink: 0;
  transition: background 0.15s;
}

.upload-back-btn:hover {
  background: #cbd5e1;
}

.upload-back-btn svg {
  stroke: #374151;
}

.upload-page-topbar-title {
  font-size: 22px;
  font-weight: 700;
  color: #111827;
  letter-spacing: 0;
}

/* ================= STEP TABS ================= */

.upload-step-tabs {
  display: flex;
  align-items: center;
  gap: 0;
  margin: 24px 32px 20px;
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 14px;
  padding: 12px 20px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.04);
}

.upload-step-tab {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 18px;
  background: transparent;
  border: none;
  border-radius: 10px;
  font-size: 14px;
  font-weight: 500;
  color: #6b7280;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s, color 0.15s;
  white-space: nowrap;
}

.upload-step-tab-active {
  background: #0f172a;
  color: #ffffff !important;
}

.upload-step-num {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: rgba(0,0,0,0.08);
  font-size: 12px;
  font-weight: 700;
}

.upload-step-tab-active .upload-step-num {
  background: rgba(255,255,255,0.25);
}

.upload-step-tab:not(.upload-step-tab-active):hover {
  background: #f1f5f9;
  color: #111827;
}

.upload-step-divider {
  flex: 1;
  height: 1px;
  background: #e2e8f0;
  margin: 0 4px;
  max-width: 40px;
}

/* ================= CONTENT AREA ================= */

.upload-content-area {
  flex: 1;
  padding: 0 32px 40px;
  background: #f0f2f5;
  overflow-y: auto;
}

/* ================= CARD ================= */

.section-card {
  background: #ffffff;
  border-radius: 16px;
  padding: 30px;
  border: 1px solid #e2e8f0;
  box-shadow: 0 4px 16px rgba(0,0,0,0.05);
}

.section-title {
  font-size: 16px;
  font-weight: 700;
  margin-bottom: 26px;
  color: #111827;
}

/* ================= FORM CONTROLS ================= */

.form-group {
  margin-bottom: 20px;
}

.form-label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: #374151;
  margin-bottom: 6px;
}

.form-control,
.custom-select,
.custom-file {
  width: 100%;
  border-radius: 10px;
  border: 1px solid #e5e7eb;
  background: #ffffff;
  height: 40px;
  padding: 0 14px;
  font-size: 14px;
  font-family: inherit;
  color: #111827;
  box-sizing: border-box;
  transition: border-color 0.2s, box-shadow 0.2s;
  -webkit-appearance: none;
  appearance: none;
}

.form-control:focus,
.custom-select:focus,
.custom-file:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 3px rgba(37,99,235,0.1);
  outline: none;
}

/* ================= NOTIFICATION BANNERS ============ */

.sn-notify {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 400;
  margin-bottom: 16px;
  border: 1px solid transparent;
}

.sn-notify-success {
  background: #dff0d8;
  border-color: #a3d98b;
  color: #2d6a2d;
}

.sn-notify-error {
  background: #fdf2f2;
  border-color: #f5b7b1;
  color: #922b21;
}

.sn-notify-icon {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  font-size: 16px;
}

.sn-notify-text {
  flex: 1;
  line-height: 1.4;
}

.sn-notify-close {
  cursor: pointer;
  font-size: 16px;
  opacity: 0.6;
  flex-shrink: 0;
  line-height: 1;
}

.sn-notify-close:hover {
  opacity: 1;
}

/* ================= TABLES ================= */

.preview-table-wrapper,
.mapping-table-wrapper {
  width: 100%;
  overflow-x: auto;
  overflow-y: auto;
  background: #ffffff;
  border: none;
  border-radius: 0;
  box-shadow: none;
}

.preview-table,
.mapping-table {
  border-collapse: collapse;
  width: 100%;
  font-size: 13px;
}

.preview-table th,
.mapping-table th {
  background: #0f172a;
  color: #ffffff;
  padding: 12px 14px;
  font-weight: 600;
  white-space: nowrap;
  position: sticky;
  top: 0;
  z-index: 2;
  border-bottom: 1px solid #e5e7eb;
}

.preview-table td,
.mapping-table td {
  padding: 10px 14px;
  border-bottom: 1px solid #f0f2f5;
  color: #374151;
  white-space: nowrap;
}

.preview-table tbody tr:hover,
.mapping-table tbody tr:hover {
  background: #eef2ff;
}

/* ================= MAPPING TABLE INPUTS ================= */

.mapping-input,
.mapping-select {
  width: 100%;
  height: 34px;
  font-size: 13px;
  border-radius: 8px;
  border: 1px solid #e5e7eb;
  background: #ffffff;
  padding: 0 10px;
  font-family: inherit;
  color: #111827;
  transition: border-color 0.2s;
}

.mapping-input:focus,
.mapping-select:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 2px rgba(37,99,235,0.1);
  outline: none;
}

.mapping-table { table-layout: fixed; }

.mapping-table td:last-child {
  text-align: center;
  vertical-align: middle;
}

/* ================= BUTTONS ================= */

.action-row {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 16px;
  padding-top: 16px;
  border-top: 1px solid #f0f2f5;
}

.mapping-action-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.upload-btn,
.save-btn,
.run-btn,
.page-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 8px 20px;
  border-radius: 8px;
  border: none;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s, transform 0.15s, opacity 0.3s;
}

.primary-btn {
  background: #0f172a;
  color: #ffffff;
}

.primary-btn:hover:not(:disabled) {
  background: #1e293b;
  transform: translateY(-1px);
}

.secondary-btn {
  background: #ffffff;
  color: #374151;
  border: 1.5px solid #d1d5db;
}

.secondary-btn:hover:not(:disabled) {
  background: #f9fafb;
  border-color: #9ca3af;
}

.page-btn {
  background: #0f172a;
  color: #ffffff;
  padding: 6px 14px;
  font-size: 13px;
}

.page-btn:disabled {
  background: #e5e7eb;
  color: #9ca3af;
  cursor: not-allowed;
  transform: none;
}

/* REQ-1, 3, 4: Faded read-only button state */
.btn-faded {
  opacity: 0.45;
  cursor: not-allowed !important;
  transform: none !important;
  pointer-events: none;
}

/* ================= ERROR CARD ================= */

.error-card {
  margin-top: 18px;
  padding: 14px;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 10px;
  font-size: 14px;
  color: #991b1b;
}

/* ================= PAGINATION ================= */

.pagination-controls {
  margin-top: 14px;
  display: flex;
  align-items: center;
  gap: 15px;
}

/* Mapping bottom row: pagination left, buttons right, same line */
.mapping-bottom-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 0;
  margin-top: 8px;
  border-top: 1px solid #f0f2f5;
}

.mapping-pagination-center {
  display: flex;
  align-items: center;
  gap: 15px;
}

.page-indicator {
  font-weight: 500;
  color: #374151;
  font-size: 14px;
}

/* ===============================================================
   METADATA MAPPING TAB
=============================================================== */

/* --- TOP: Disclaimer box --- */

.disclaimer-box {
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 10px;
  padding: 18px 22px;
  margin-bottom: 16px;
  box-shadow: 0 4px 16px rgba(0,0,0,0.05);
}

.disclaimer-text {
  font-size: 13px;
  color: #111827;
  line-height: 1.6;
  margin-bottom: 16px;
}

.disclaimer-header-row {
  display: flex;
  align-items: center;
  padding-left: 18px;
  margin-bottom: 8px;
}

.dis-col-target {
  width: 200px;
  font-size: 14px;
  font-weight: 700;
  color: #111827;
  flex-shrink: 0;
}

.dis-col-source {
  font-size: 14px;
  font-weight: 700;
  color: #111827;
}

.disclaimer-field-row {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 10px;
}

.dis-target-cell {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
}

.dis-target-box {
  width: 180px;
  height: 36px;
  border: 1.5px solid #374151;
  border-radius: 6px;
  display: flex;
  align-items: center;
  padding: 0 12px;
  font-size: 14px;
  font-weight: 600;
  color: #111827;
  background: #ffffff;
  box-sizing: border-box;
}

.dis-source-cell {
  flex: 1;
  max-width: 280px;
}

.dis-select {
  width: 100%;
  height: 36px;
  border: 1px solid #d1d5db;
  border-radius: 6px;
  background: #ffffff;
  font-size: 13px;
  font-family: inherit;
  color: #374151;
  padding: 0 10px;
  box-sizing: border-box;
  cursor: pointer;
}

.dis-select:focus {
  border-color: #2563eb;
  outline: none;
}

.req-star {
  color: #c0392b;
  font-size: 16px;
  font-weight: 700;
  line-height: 1;
  flex-shrink: 0;
}

/* --- BOTTOM: Mapping table --- */

.mapping-body-layout {
  width: 100%;
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 12px;
  box-shadow: 0 4px 16px rgba(0,0,0,0.05);
  overflow: hidden;
}

.sdname-col {
  display: table-cell;
  width: 190px;
  vertical-align: top;
  border-right: none;
}

.sdname-label {
  background: #0f172a;
  color: #ffffff;
  font-size: 13px;
  font-weight: 600;
  padding: 12px 14px;
  border-bottom: 1px solid #1e293b;
  white-space: nowrap;
  min-height: 44px;
  display: flex;
  align-items: center;
  box-sizing: border-box;
}

.sdname-item {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 10px 10px;
  border-bottom: 1px solid #f0f2f5;
  min-height: 54px;
  box-sizing: border-box;
}

.sdname-input {
  flex: 1;
  height: 34px;
  border: 1px solid #e5e7eb;
  border-radius: 6px;
  background: #ffffff;
  font-size: 13px;
  font-family: inherit;
  color: #111827;
  padding: 0 8px;
  box-sizing: border-box;
  min-width: 0;
}

.sdname-input:focus {
  border-color: #2563eb;
  outline: none;
}

.sdname-select {
  flex: 1;
  height: 34px;
  border: 1px solid #e5e7eb;
  border-radius: 6px;
  background: #ffffff;
  font-size: 13px;
  font-family: inherit;
  color: #111827;
  padding: 0 8px;
  box-sizing: border-box;
  min-width: 0;
  cursor: pointer;
}

.sdname-select:focus {
  border-color: #2563eb;
  outline: none;
}

/* RIGHT column — mapping table + controls */
.mapping-right-col {
  display: block;
  width: 100%;
  padding: 0;
}

.mapping-table td .req-star {
  margin-right: 4px;
  vertical-align: middle;
}

sp_widget.script:
(function() {

    data.dataModels = [];
		data.objectTables = [];
    data.targetFields = [];
    data.previewHeaders = [];
    data.previewRows = [];
    data.totalPreviewCount = 0;
    data.error = "";
    data.message = "";
    data.success = false;

    if (!gs.hasRole('x_ctans_incentnow.admin')) {
        data.error = "Access Denied";
        return;
    }


		data.sourceTypeOptions=[];
		var grChoice = new GlideRecordSecure("sys_choice");
		grChoice.addEncodedQuery("name=x_ctans_incentnow_data_model_object^element=source_type^inactive=false^language=en");
		grChoice.query();
		while(grChoice.next())
			{
				var obj={};
				obj.label=grChoice.getValue("label");
				obj.value=grChoice.getValue("value");
				data.sourceTypeOptions.push(obj);
			}

	data.sourcesystem=[];
		var grChoice = new GlideRecordSecure("sys_choice");
		grChoice.addEncodedQuery("name=x_ctans_incentnow_data_model_object^element=data_source_system^inactive=false^language=en");
		grChoice.query();
		while(grChoice.next())
			{
				var obj={};
				obj.label=grChoice.getValue("label");
				obj.value=grChoice.getValue("value");
				data.sourcesystem.push(obj);
			}

    /* -------------- CREATE MODEL -------------- */

    if (input && input.action === 'createModel') {


        if (!input.model ||
            !input.model.source_name ||
            !input.model.source_type ||
            !input.model.object_name
					 || !input.model.data_source_system) {
            data.error = "All fields are required.";
            data.success = false;
            return;
        }

        var check = new GlideRecordSecure('x_ctans_incentnow_data_model_object');
        check.addQuery('source_name', input.model.source_name);
        check.addQuery('object_name', input.model.object_name);
        check.query();

        if (check.next()) {

						data.newModelId=check.getUniqueValue();
            data.error = "Model already exists.";
            data.success = false;
            return;
        }

        var dm = new GlideRecordSecure('x_ctans_incentnow_data_model_object');
        dm.initialize();
        dm.source_name = input.model.source_name;
        dm.source_type = input.model.source_type;
        dm.object_name = input.model.object_name;
				dm.data_source_system = input.model.data_source_system;
			//gs.addErrorMessage("table "+input.model.objectTable);
				dm.object_table = input.model.objectTable.sys_id;
        dm.active = true;
        var newId = dm.insert();
				if(newId)
					{
						//gs.addInfoMessage('Data Model Created Successfully:');
        		data.success    = true;
						data.error      = "";
						data.message    = "Data Model Created Successfully";
						data.newModelId   = newId + '';
						data.newModelName = input.model.source_name + " - " + input.model.object_name;
					}
			else
				{
					data.success=false;
					data.newModelName = input.model.source_name + " - " + input.model.object_name;
					data.error= "Insertion failed :- "+data.newModelName;
					data.message    = "Insertion failed :- "+data.newModelName;


				}


        return;
    }

    /* -------------- GET DATA MODELS -------------- */

    if (input && input.action === 'getDataModels') {

        var dmList = new GlideRecordSecure('x_ctans_incentnow_data_model_object');
        dmList.addQuery('active', true);
        dmList.orderBy('object_name');
        dmList.query();

        while (dmList.next()) {
            data.dataModels.push({
                sys_id: dmList.getUniqueValue(),
                name: dmList.source_name + " - " + dmList.object_name
            });
        }
        return;
    }

	/* -------------- GET OBJECT TABLE -------------- */

	if (input && input.action === 'getObjectTables') {

		var incentiqtable=gs.getProperty("x_ctans_incentnow.internal.crm_tables");

        var dmList = new GlideRecordSecure('sys_db_object');
					dmList.addEncodedQuery("nameIN"+incentiqtable);
				//dmList.addEncodedQuery("label=Quote^ORlabel=Opportunity^ORlabel=Order^ORlabel=Install Base^ORlabel=Contract^ORlabel=Case^ORlabel=Work Order")
        dmList.orderBy('label');
        dmList.query();
        while (dmList.next()) {
            data.objectTables.push({
                name: dmList.getValue('name'),
                label: dmList.getValue('label'),
								sys_id: dmList.getUniqueValue()
            });
        }
    }




	if (input && input.action === 'getOpportunityFields') {

			var table_name= input.table_name;
		//gs.addErrorMessage(table_name)

				var dictGR = new GlideRecordSecure('sys_dictionary');
				dictGR.addQuery('name', table_name);
				dictGR.addQuery('active', true);
				dictGR.addNotNullQuery('element');
				dictGR.addEncodedQuery("internal_type!=GUID^internal_type!=collection");
				dictGR.orderBy('column_label');
				dictGR.query();

				while (dictGR.next()) {



						var internalType = dictGR.getValue('internal_type');

						var fieldTypeSysId = '';

						var typeGR = new GlideRecordSecure('sys_glide_object');
						typeGR.addQuery('name', internalType);
						typeGR.query();

						if (typeGR.next()) {
						fieldTypeSysId = typeGR.getUniqueValue();
						}

						data.previewHeaders.push({
						name: dictGR.getValue('element'),
						label: dictGR.getValue('column_label'),
						internal_type: internalType,
						field_type_sys_id: fieldTypeSysId
						});

				}

				return;


			}

	if (input && input.action === 'getDataTypes') {

		data.dataTypes=[];
			var typeGR = new GlideRecordSecure('sys_glide_object');

			typeGR.orderBy('name');
			typeGR.query();
			//gs.addErrorMessage("rowcount "+typeGR.getRowCount())
			while (typeGR.next()) {

					data.dataTypes.push({
							label: typeGR.getValue('label'),
							value: typeGR.getValue('name'),
							sys_id: typeGR.getUniqueValue()
					});
			}




			}


    /* -------------- GET TARGET FIELDS -------------- */

    if (input && input.action === 'getTargetFields') {

        if (!input.dataType) return;

        var typeGR = new GlideRecordSecure('sys_glide_object');
        typeGR.addQuery('name', input.dataType);
        typeGR.query();
        if (!typeGR.next()) return;

        var fieldTypeSysId = typeGR.getUniqueValue();
        var util = new DataLakeUtils();
        var encodedQuery = util.filterColumnsbyType(fieldTypeSysId);

        var dictGR = new GlideRecordSecure('sys_dictionary');
        dictGR.addEncodedQuery(encodedQuery);
        dictGR.query();

        while (dictGR.next()) {
            data.targetFields.push({
                name: dictGR.getValue('element'),
                label: dictGR.getValue('column_label')
            });
        }
        return;
    }

    /* -------------- SAVE MAPPING -------------- */

    if (input && input.action === 'saveMapping') {

        if (!input.dataModelObject || !input.mappings || !input.mappings.length) {


            data.error = "Invalid mapping payload.";
            return;
        }


       // var old = new GlideRecordSecure('x_ctans_incentnow_metadata_mapping');
       // old.addQuery('data_model_object_id', input.dataModelObject);
       // old.deleteMultiple();
				//gs.addErrorMessage(JSON.stringify(input.mappings));
        for (var i = 0; i < input.mappings.length; i++) {
            var m = input.mappings[i];


            var grMap = new GlideRecordSecure('x_ctans_incentnow_metadata_mapping');

						grMap.addQuery('data_model_object_id', input.dataModelObject);
						grMap.addQuery('source_field_name', m.source.trim());
						grMap.query();

						var isUpdate = grMap.next();

						if (!isUpdate) {
								grMap.initialize();
						}

            grMap.data_model_object_id = input.dataModelObject;
            grMap.source_field_name = m.source.trim();
						grMap.field_type = m.fieldTypeSysId;
            grMap.source_display_name = m.sourceDisplayName || m.source;
            grMap.is_primary_key = m.isPrimary ? true : false;
            grMap.active = true;
						grMap.data_lake_field_name="";

					if (m.targetField) {

							var dict = new GlideRecordSecure('sys_dictionary');
							dict.addQuery('name', 'x_ctans_incentnow_data_lake');
							dict.addQuery('element', m.targetField);
							dict.query();

							if (dict.next()) {
									grMap.data_lake_field_name = dict.getUniqueValue();
									//grMap.data_lake_column_name = dict.getValue('element');
							}
					}
					else
						grMap.data_lake_field_name = "";


            if (isUpdate) {
								grMap.update();
						} else {
								grMap.insert();
						}
        }

        gs.addInfoMessage("Mapping Saved Successfully");

    }


    /* -------------- RUN TRANSFORM -------------- */



})();
